"""The security boundary: attestation validation, approval counting, revocation.

Every consumer verifies from the signed log alone (DESIGN.md §6.5). Relay
enforcement — group membership, private-read gating, event deletion — is an
optimization, never an assumption: a plain relay may serve stale, revoked,
or hostile events, and these helpers are the reader-side bound on trusting
them.

Attestation follows NIP-OA (restated in docs/kinds/nip-oa-attestation.md):
an optional ``auth`` tag by which an owner key authorizes the agent key that
authored the event. Verification here never consults a wall clock —
``created_at`` clauses constrain the event's self-declared timestamp, which
the agent controls, so wall-clock freshness is a caller concern by design.
"""

from __future__ import annotations

import hashlib
import re
from dataclasses import dataclass
from enum import Enum, unique
from typing import Iterable, Literal, NamedTuple

import lindenmayer.core.keys as _keys
from lindenmayer.core.event import Event
from lindenmayer.core.kinds.constants import KIND_APPROVAL_VERDICT

__all__ = [
    "ApprovalCounts",
    "AttestationLabel",
    "AttestationOutcome",
    "AttestationResult",
    "AttestationState",
    "attestation_state",
    "count_approvals",
    "filter_attested",
    "is_approved",
    "validate_attestation",
]

AUTH_TAG_NAME = "auth"
_AUTH_DOMAIN = "nostr:agent-auth:"

# Strict per-clause grammar: canonical decimals only. ``fullmatch`` with an
# explicit digit class rejects unicode digits, leading zeros, signs, and
# whitespace that ``str.isdigit()``-based parsing would let through.
_CLAUSE_RE = re.compile(r"(kind=|created_at<|created_at>)(0|[1-9][0-9]*)")

_KIND_MAX = 65535
_CREATED_AT_MAX = 4294967295


def _is_hex(value: str, length: int) -> bool:
    if len(value) != length or value != value.lower():
        return False
    try:
        bytes.fromhex(value)
    except ValueError:
        return False
    return True


# -- attestation validation ------------------------------------------------


@unique
class AttestationOutcome(Enum):
    """Tri-state result of NIP-OA auth-tag validation."""

    VALID = "valid"
    ABSENT = "absent"
    INVALID = "invalid"


@dataclass(frozen=True, slots=True)
class AttestationResult:
    """Outcome plus the machine-readable ``reason`` when INVALID.

    ``owner_pubkey`` and ``conditions`` are populated only for VALID —
    an invalid tag's claims are not facts and are deliberately withheld.
    """

    outcome: AttestationOutcome
    owner_pubkey: str | None = None
    conditions: str | None = None
    reason: str | None = None


def _parse_conditions(conditions: str) -> list[tuple[str, int]] | None:
    """Parse a NIP-OA conditions string strictly; None on any violation.

    The empty string is valid (no clauses). The raw string is what the
    owner signed — callers must never reorder, dedupe, or normalize it.
    """
    if conditions == "":
        return []
    clauses: list[tuple[str, int]] = []
    for segment in conditions.split("&"):
        match = _CLAUSE_RE.fullmatch(segment)
        if match is None:
            return None
        op, number = match.group(1), int(match.group(2))
        limit = _KIND_MAX if op == "kind=" else _CREATED_AT_MAX
        if number > limit:
            return None
        clauses.append((op, number))
    return clauses


def _clause_satisfied(event: Event, op: str, number: int) -> bool:
    if op == "kind=":
        return event.kind == number
    if op == "created_at<":
        return event.created_at < number
    return event.created_at > number


def validate_attestation(event: Event) -> AttestationResult:
    """Validate the NIP-OA ``auth`` tag on ``event`` from the signed log alone.

    Order matters: the event's own NIP-01 validity comes first (a valid auth
    tag on an invalid event establishes nothing), then tag shape, then the
    owner signature over ``sha256("nostr:agent-auth:" + event.pubkey + ":"
    + conditions)``, then every clause evaluated against the event (AND).
    """
    _invalid = lambda reason: AttestationResult(  # noqa: E731 — local shorthand
        outcome=AttestationOutcome.INVALID, reason=reason
    )
    if not event.verify():
        return _invalid("invalid_event")
    auth_tags = [tag for tag in event.tags if tag and tag[0] == AUTH_TAG_NAME]
    if not auth_tags:
        return AttestationResult(outcome=AttestationOutcome.ABSENT)
    if len(auth_tags) > 1:
        return _invalid("duplicate_auth_tag")
    tag = auth_tags[0]
    if len(tag) != 4:
        return _invalid("malformed_tag")
    owner_pubkey, conditions, sig_hex = tag[1], tag[2], tag[3]
    if not _is_hex(owner_pubkey, 64):
        return _invalid("invalid_owner_pubkey")
    if not _is_hex(sig_hex, 128):
        return _invalid("invalid_sig_encoding")
    if owner_pubkey == event.pubkey:
        return _invalid("self_attestation")
    clauses = _parse_conditions(conditions)
    if clauses is None:
        return _invalid("invalid_conditions")
    preimage = f"{_AUTH_DOMAIN}{event.pubkey}:{conditions}".encode("utf-8")
    message = hashlib.sha256(preimage).digest()
    if not _keys.schnorr_verify(owner_pubkey, message, bytes.fromhex(sig_hex)):
        return _invalid("invalid_owner_signature")
    for op, number in clauses:
        if not _clause_satisfied(event, op, number):
            return _invalid("condition_unsatisfied")
    return AttestationResult(
        outcome=AttestationOutcome.VALID,
        owner_pubkey=owner_pubkey,
        conditions=conditions,
    )


# -- approval counting -----------------------------------------------------


class ApprovalCounts(NamedTuple):
    """Verdict tally for one approval request (kind 42040)."""

    approve_count: int
    reject_count: int
    per_approver: dict[str, Literal["approve", "reject"]]


def _verdict_value(event: Event) -> str | None:
    """The single ``verdict`` tag value, or None if absent or ambiguous.

    The kind-42041 schema (docs/kinds/) carries the verdict in exactly one
    ``verdict`` tag; an event with zero or several is not a valid verdict.
    """
    values = [vals[0] for vals in event.tag_values("verdict") if vals]
    return values[0] if len(values) == 1 else None


def count_approvals(request: Event, events: Iterable[Event]) -> ApprovalCounts:
    """Count signed verdicts (kind 42041) answering ``request``.

    A candidate must verify under NIP-01, ``e``-tag the request id, and carry
    a ``verdict`` tag of exactly ``approve`` or ``reject`` — anything else is
    excluded, not counted either way. Per approver (``event.pubkey``) the
    latest verdict wins, ordered by ``created_at`` descending with ascending
    id as the tiebreak, so reject→revise→approve chains resolve to the final
    word deterministically on every reader.
    """
    latest: dict[str, Event] = {}
    for event in events:
        if event.kind != KIND_APPROVAL_VERDICT:
            continue
        verdict = _verdict_value(event)
        if verdict not in ("approve", "reject"):
            continue
        if not any(vals and vals[0] == request.id for vals in event.tag_values("e")):
            continue
        if not event.verify():
            continue
        current = latest.get(event.pubkey)
        if (
            current is None
            or event.created_at > current.created_at
            or (event.created_at == current.created_at and event.id < current.id)
        ):
            latest[event.pubkey] = event
    per_approver: dict[str, Literal["approve", "reject"]] = {
        pubkey: "approve" if _verdict_value(event) == "approve" else "reject"
        for pubkey, event in latest.items()
    }
    approves = sum(1 for v in per_approver.values() if v == "approve")
    return ApprovalCounts(
        approve_count=approves,
        reject_count=len(per_approver) - approves,
        per_approver=per_approver,
    )


def is_approved(
    request: Event,
    events: Iterable[Event],
    threshold: int,
    required_approvers: Iterable[str] | None = None,
) -> bool:
    """Does ``request`` have >= ``threshold`` standing approvals?

    With ``required_approvers``, only verdicts from that set count — a
    merge-gate caller names its reviewers; everyone else is advisory. This
    helper only counts the signed log: *enforcing* the gate (refusing a
    merge) is a bridge/process concern layered above these events.
    """
    counts = count_approvals(request, events)
    per_approver = counts.per_approver
    if required_approvers is not None:
        allowed = set(required_approvers)
        per_approver = {k: v for k, v in per_approver.items() if k in allowed}
    return sum(1 for v in per_approver.values() if v == "approve") >= threshold


# -- revocation filtering and extraction labeling --------------------------


@unique
class AttestationState(Enum):
    """Trust label for a stored event row (extraction pipeline, DESIGN.md §4)."""

    ATTESTED = "attested"
    UNATTESTED = "unattested"
    REVOKED = "revoked"
    INVALID_ATTESTATION = "invalid_attestation"
    INVALID_EVENT = "invalid_event"


@dataclass(frozen=True, slots=True)
class AttestationLabel:
    """An ``AttestationState`` plus its provenance details.

    ``reason`` carries the ``validate_attestation`` reason verbatim for
    INVALID_ATTESTATION rows; ``owner_pubkey`` is set only when the auth
    tag validated (including REVOKED-by-owner rows, where the owner is
    exactly the fact that matters).
    """

    state: AttestationState
    owner_pubkey: str | None = None
    reason: str | None = None


def attestation_state(
    event: Event,
    revoked_owners: frozenset[str] | set[str] = frozenset(),
    revoked_agents: frozenset[str] | set[str] = frozenset(),
) -> AttestationLabel:
    """Label ``event`` for read-time trust decisions and corpus extraction.

    Agent revocation deliberately applies even to events with no auth tag:
    the reader-side trust bound bounds the *key*, not just the attestation
    claim — a banned agent key does not regain neutrality by omitting its
    provenance tag. Owner revocation, by contrast, can only apply where an
    owner is validly claimed.
    """
    if not event.verify():
        return AttestationLabel(state=AttestationState.INVALID_EVENT, reason="invalid_event")
    result = validate_attestation(event)
    if result.outcome is AttestationOutcome.ABSENT:
        if event.pubkey in revoked_agents:
            return AttestationLabel(state=AttestationState.REVOKED)
        return AttestationLabel(state=AttestationState.UNATTESTED)
    if result.outcome is AttestationOutcome.VALID:
        if result.owner_pubkey in revoked_owners or event.pubkey in revoked_agents:
            return AttestationLabel(
                state=AttestationState.REVOKED, owner_pubkey=result.owner_pubkey
            )
        return AttestationLabel(
            state=AttestationState.ATTESTED, owner_pubkey=result.owner_pubkey
        )
    return AttestationLabel(state=AttestationState.INVALID_ATTESTATION, reason=result.reason)


def filter_attested(
    events: Iterable[Event],
    revoked_owners: frozenset[str] | set[str] = frozenset(),
    revoked_agents: frozenset[str] | set[str] = frozenset(),
) -> list[Event]:
    """Keep events a reader may trust: ATTESTED or UNATTESTED, in order.

    Drops INVALID_EVENT, INVALID_ATTESTATION, and REVOKED rows.

    Revocation latency caveat (degradation.md): a plain relay still serves
    revoked or stale events after the fact — revocation propagates only as
    fast as readers refresh their revocation sets and re-filter. This
    function is that reader-side bound, not relay enforcement; deployments
    needing hard deletion must verify that capability separately
    (``CoreConfig`` capability attestations) rather than assume it.
    """
    keep = (AttestationState.ATTESTED, AttestationState.UNATTESTED)
    return [
        event
        for event in events
        if attestation_state(event, revoked_owners, revoked_agents).state in keep
    ]

"""Typed models for Lindenmayer's eight custom kinds.

Wire shapes follow docs/research/relay-integration/event-kinds.md §2
exactly; the portable per-kind specs live in docs/kinds/. Privacy is a
wire-format property here: run accounting is one rolled-up event per run
(no per-step model exists), and nothing in this API takes a per-worker
identity — ephemeral workers author no events.
"""

from __future__ import annotations

import re
from datetime import datetime
from typing import Any, Literal

from pydantic import Field, field_validator

from lindenmayer.core.event import Event
from lindenmayer.core.kinds import constants
from lindenmayer.core.kinds.base import KindModel, KindValidationError

__all__ = [
    "NodeLifecycle",
    "NodeStatePointer",
    "RunAccounting",
    "SubgraphDigest",
    "ApprovalRequest",
    "ApprovalVerdict",
    "TemplateVersion",
    "TemplatePointer",
]

_HEX64 = re.compile(r"^[0-9a-f]{64}$")


def _check_hex64(value: str, what: str) -> str:
    if not _HEX64.fullmatch(value):
        raise ValueError(f"{what} must be 64-char lowercase hex, got {value!r}")
    return value


def _check_iso8601(value: str, what: str) -> str:
    try:
        datetime.fromisoformat(value)
    except ValueError as exc:
        raise ValueError(f"{what} must be an ISO 8601 timestamp: {exc}") from exc
    return value


class NodeLifecycle(KindModel):
    """Kind 42010 — one append-only event per node status transition."""

    KIND = constants.KIND_NODE_LIFECYCLE

    branch: str = Field(min_length=1)
    status: str = Field(min_length=1)
    run: str = Field(min_length=1)
    reason: str = ""
    parent_pubkey: str | None = None
    prev_event_id: str | None = None

    @field_validator("parent_pubkey")
    @classmethod
    def _v_parent(cls, v: str | None) -> str | None:
        return None if v is None else _check_hex64(v, "parent_pubkey")

    @field_validator("prev_event_id")
    @classmethod
    def _v_prev(cls, v: str | None) -> str | None:
        return None if v is None else _check_hex64(v, "prev_event_id")

    def event_tags(self) -> list[list[str]]:
        tags = [
            ["branch", self.branch],
            ["status", self.status],
            ["run", self.run],
        ]
        if self.parent_pubkey is not None:
            tags.append(["p", self.parent_pubkey])
        if self.prev_event_id is not None:
            tags.append(["e", self.prev_event_id])
        return tags

    def event_content(self) -> str:
        return self._dump_content({"reason": self.reason})

    @classmethod
    def _from_wire(cls, event: Event) -> dict[str, Any]:
        content = cls._content_object(event)
        return {
            "branch": cls._require_tag(event, "branch"),
            "status": cls._require_tag(event, "status"),
            "run": cls._require_tag(event, "run"),
            "parent_pubkey": event.first_tag_value("p"),
            "prev_event_id": event.first_tag_value("e"),
            "reason": content.get("reason", ""),
        }


class NodeStatePointer(KindModel):
    """Kind 38110 — addressable latest-state snapshot, ``d`` = branch name."""

    KIND = constants.KIND_NODE_STATE_POINTER

    branch: str = Field(min_length=1)  # the addressable `d` key
    status: str = Field(min_length=1)
    run: str = Field(min_length=1)
    iter: str = Field(min_length=1)
    cost_shadow_usd: float = Field(ge=0)
    cost_cap_usd: float = Field(ge=0)
    last_lifecycle_event: str

    @field_validator("last_lifecycle_event")
    @classmethod
    def _v_last(cls, v: str) -> str:
        return _check_hex64(v, "last_lifecycle_event")

    def event_tags(self) -> list[list[str]]:
        return [
            ["d", self.branch],
            ["status", self.status],
            ["run", self.run],
            ["iter", self.iter],
        ]

    def event_content(self) -> str:
        return self._dump_content(
            {
                "cost_shadow_usd": self.cost_shadow_usd,
                "cost_cap_usd": self.cost_cap_usd,
                "last_lifecycle_event": self.last_lifecycle_event,
            }
        )

    @classmethod
    def _from_wire(cls, event: Event) -> dict[str, Any]:
        content = cls._content_object(event)
        return {
            "branch": cls._require_tag(event, "d"),
            "status": cls._require_tag(event, "status"),
            "run": cls._require_tag(event, "run"),
            "iter": cls._require_tag(event, "iter"),
            "cost_shadow_usd": content.get("cost_shadow_usd"),
            "cost_cap_usd": content.get("cost_cap_usd"),
            "last_lifecycle_event": content.get("last_lifecycle_event"),
        }


class RunAccounting(KindModel):
    """Kind 42020 — one rolled-up accounting event per completed run.

    Deliberately run-grained: no per-step fields exist anywhere in this
    API (aggregates flow up, details stay in the subgraph). Costs are
    shadow cost, never real spend.
    """

    KIND = constants.KIND_RUN_ACCOUNTING

    branch: str = Field(min_length=1)
    run: str = Field(min_length=1)
    iter_count: int = Field(ge=0)
    cost_shadow_usd: float = Field(ge=0)
    duration_s: float = Field(ge=0)
    exit_status: Literal["completed", "exited", "killed"]
    template: str | None = None  # template version event id, when template-spawned

    @field_validator("template")
    @classmethod
    def _v_template(cls, v: str | None) -> str | None:
        return None if v is None else _check_hex64(v, "template")

    def event_tags(self) -> list[list[str]]:
        tags = [["branch", self.branch], ["run", self.run]]
        if self.template is not None:
            tags.append(["template", self.template])
        return tags

    def event_content(self) -> str:
        return self._dump_content(
            {
                "iter_count": self.iter_count,
                "cost_shadow_usd": self.cost_shadow_usd,
                "duration_s": self.duration_s,
                "exit_status": self.exit_status,
            }
        )

    @classmethod
    def _from_wire(cls, event: Event) -> dict[str, Any]:
        content = cls._content_object(event)
        return {
            "branch": cls._require_tag(event, "branch"),
            "run": cls._require_tag(event, "run"),
            "template": event.first_tag_value("template"),
            "iter_count": content.get("iter_count"),
            "cost_shadow_usd": content.get("cost_shadow_usd"),
            "duration_s": content.get("duration_s"),
            "exit_status": content.get("exit_status"),
        }


class SubgraphDigest(KindModel):
    """Kind 42030 — periodic aggregate a persistent node publishes about
    its own subtree. No per-child breakdown, by design."""

    KIND = constants.KIND_SUBGRAPH_DIGEST

    branch: str = Field(min_length=1)
    period_start: str
    period_end: str
    child_count: int = Field(ge=0)
    active: int = Field(ge=0)
    exited: int = Field(ge=0)
    completed: int = Field(ge=0)
    stuck_flagged: int = Field(ge=0)
    subtree_cost_shadow_usd: float = Field(ge=0)

    @field_validator("period_start")
    @classmethod
    def _v_start(cls, v: str) -> str:
        return _check_iso8601(v, "period_start")

    @field_validator("period_end")
    @classmethod
    def _v_end(cls, v: str) -> str:
        return _check_iso8601(v, "period_end")

    def event_tags(self) -> list[list[str]]:
        return [
            ["branch", self.branch],
            ["period_start", self.period_start],
            ["period_end", self.period_end],
        ]

    def event_content(self) -> str:
        return self._dump_content(
            {
                "child_count": self.child_count,
                "active": self.active,
                "exited": self.exited,
                "completed": self.completed,
                "stuck_flagged": self.stuck_flagged,
                "subtree_cost_shadow_usd": self.subtree_cost_shadow_usd,
            }
        )

    @classmethod
    def _from_wire(cls, event: Event) -> dict[str, Any]:
        content = cls._content_object(event)
        return {
            "branch": cls._require_tag(event, "branch"),
            "period_start": cls._require_tag(event, "period_start"),
            "period_end": cls._require_tag(event, "period_end"),
            "child_count": content.get("child_count"),
            "active": content.get("active"),
            "exited": content.get("exited"),
            "completed": content.get("completed"),
            "stuck_flagged": content.get("stuck_flagged"),
            "subtree_cost_shadow_usd": content.get("subtree_cost_shadow_usd"),
        }


class ApprovalRequest(KindModel):
    """Kind 42040 — a ``requires_approval`` step asking its approver."""

    KIND = constants.KIND_APPROVAL_REQUEST

    branch: str = Field(min_length=1)
    run: str = Field(min_length=1)
    iter: str = Field(min_length=1)
    step: str = Field(min_length=1)
    approver_pubkey: str
    step_name: str = Field(min_length=1)
    summary: str

    @field_validator("approver_pubkey")
    @classmethod
    def _v_approver(cls, v: str) -> str:
        return _check_hex64(v, "approver_pubkey")

    def event_tags(self) -> list[list[str]]:
        return [
            ["branch", self.branch],
            ["run", self.run],
            ["iter", self.iter],
            ["step", self.step],
            ["p", self.approver_pubkey],
        ]

    def event_content(self) -> str:
        return self._dump_content({"step_name": self.step_name, "summary": self.summary})

    @classmethod
    def _from_wire(cls, event: Event) -> dict[str, Any]:
        content = cls._content_object(event)
        return {
            "branch": cls._require_tag(event, "branch"),
            "run": cls._require_tag(event, "run"),
            "iter": cls._require_tag(event, "iter"),
            "step": cls._require_tag(event, "step"),
            "approver_pubkey": cls._require_tag(event, "p"),
            "step_name": content.get("step_name"),
            "summary": content.get("summary"),
        }


class ApprovalVerdict(KindModel):
    """Kind 42041 — answers a request by ``e``-tagging it; append-only so
    reject→revise→approve chains stay threaded."""

    KIND = constants.KIND_APPROVAL_VERDICT

    request_id: str
    verdict: Literal["approve", "reject"]
    rationale: str

    @field_validator("request_id")
    @classmethod
    def _v_request(cls, v: str) -> str:
        return _check_hex64(v, "request_id")

    def event_tags(self) -> list[list[str]]:
        return [["e", self.request_id], ["verdict", self.verdict]]

    def event_content(self) -> str:
        return self._dump_content({"rationale": self.rationale})

    @classmethod
    def _from_wire(cls, event: Event) -> dict[str, Any]:
        content = cls._content_object(event)
        return {
            "request_id": cls._require_tag(event, "e"),
            "verdict": cls._require_tag(event, "verdict"),
            "rationale": content.get("rationale"),
        }


class TemplateVersion(KindModel):
    """Kind 42050 — one immutable event per registered template version."""

    KIND = constants.KIND_TEMPLATE_VERSION

    template_name: str = Field(min_length=1)
    version: str = Field(min_length=1)
    summary: str
    inherits: str | None = None  # parent template version event id
    git_ref: str | None = None

    @field_validator("inherits")
    @classmethod
    def _v_inherits(cls, v: str | None) -> str | None:
        return None if v is None else _check_hex64(v, "inherits")

    def event_tags(self) -> list[list[str]]:
        tags = [["template_name", self.template_name], ["version", self.version]]
        if self.inherits is not None:
            # NIP-10 style marked e-tag: ["e", <id>, <relay-url>, <marker>]
            tags.append(["e", self.inherits, "", "inherit"])
        if self.git_ref is not None:
            tags.append(["git_ref", self.git_ref])
        return tags

    def event_content(self) -> str:
        return self._dump_content({"summary": self.summary})

    @classmethod
    def _from_wire(cls, event: Event) -> dict[str, Any]:
        content = cls._content_object(event)
        inherits = None
        for values in event.tag_values("e"):
            if len(values) >= 3 and values[2] == "inherit":
                inherits = values[0]
                break
        return {
            "template_name": cls._require_tag(event, "template_name"),
            "version": cls._require_tag(event, "version"),
            "inherits": inherits,
            "git_ref": event.first_tag_value("git_ref"),
            "summary": content.get("summary"),
        }


class TemplatePointer(KindModel):
    """Kind 38150 — addressable pointer to the current template version,
    ``d`` = template name. Pure indirection: content is empty."""

    KIND = constants.KIND_TEMPLATE_POINTER

    template_name: str = Field(min_length=1)  # the addressable `d` key
    version_event_id: str

    @field_validator("version_event_id")
    @classmethod
    def _v_version(cls, v: str) -> str:
        return _check_hex64(v, "version_event_id")

    def event_tags(self) -> list[list[str]]:
        return [["d", self.template_name], ["e", self.version_event_id]]

    def event_content(self) -> str:
        return ""

    @classmethod
    def _from_wire(cls, event: Event) -> dict[str, Any]:
        # Spec: content is empty or "{}" — anything else is malformed.
        if event.content not in ("", "{}"):
            raise KindValidationError(
                f"kind {cls.KIND} (TemplatePointer) content must be empty or '{{}}', "
                f"got {event.content!r}"
            )
        return {
            "template_name": cls._require_tag(event, "d"),
            "version_event_id": cls._require_tag(event, "e"),
        }

"""NIP-01 event model — the trust root of the platform.

Canonical id computation, signing, and verification for Nostr events.
Every other Lindenmayer component consumes events through this module;
nothing here knows about Lindenmayer kinds, relays, or Buzz.

Canonical serialization follows NIP-01: the id is the SHA-256 of the
UTF-8 JSON array ``[0, pubkey, created_at, kind, tags, content]`` with no
whitespace. Python's ``json.dumps(ensure_ascii=False, separators=(",", ":"))``
produces the same escaping as ``JSON.stringify`` (the de-facto reference
via nostr-tools), which is what published event ids are computed with.
"""

from __future__ import annotations

import hashlib
import json
import time
from dataclasses import dataclass, field
from typing import Any, Iterator

import lindenmayer.core.keys as _keys

__all__ = ["Event", "EventValidationError", "canonical_serialization", "compute_event_id"]


class EventValidationError(ValueError):
    """Raised when an event fails structural validation."""


def canonical_serialization(
    pubkey: str, created_at: int, kind: int, tags: list[list[str]], content: str
) -> bytes:
    """The NIP-01 canonical byte serialization whose SHA-256 is the event id."""
    return json.dumps(
        [0, pubkey, created_at, kind, tags, content],
        ensure_ascii=False,
        separators=(",", ":"),
    ).encode("utf-8")


def compute_event_id(
    pubkey: str, created_at: int, kind: int, tags: list[list[str]], content: str
) -> str:
    """Lowercase hex SHA-256 of the canonical serialization."""
    return hashlib.sha256(
        canonical_serialization(pubkey, created_at, kind, tags, content)
    ).hexdigest()


def _is_hex(value: str, length: int) -> bool:
    if len(value) != length or value != value.lower():
        return False
    try:
        bytes.fromhex(value)
    except ValueError:
        return False
    return True


@dataclass(frozen=True, slots=True)
class Event:
    """An immutable NIP-01 event.

    ``tags`` is stored as a tuple of tuples so instances are hashable; the
    wire form (``to_dict``/``to_json``) uses lists per NIP-01.
    """

    pubkey: str
    created_at: int
    kind: int
    tags: tuple[tuple[str, ...], ...]
    content: str
    id: str
    sig: str | None = field(default=None)

    # -- construction ------------------------------------------------------

    @classmethod
    def build(
        cls,
        *,
        pubkey: str,
        kind: int,
        tags: list[list[str]] | tuple[tuple[str, ...], ...] = (),
        content: str = "",
        created_at: int | None = None,
    ) -> "Event":
        """Build an unsigned event with a freshly computed id."""
        ts = int(time.time()) if created_at is None else int(created_at)
        tag_lists = [list(t) for t in tags]
        event_id = compute_event_id(pubkey, ts, kind, tag_lists, content)
        return cls(
            pubkey=pubkey,
            created_at=ts,
            kind=kind,
            tags=tuple(tuple(t) for t in tags),
            content=content,
            id=event_id,
        )

    @classmethod
    def from_dict(cls, data: dict[str, Any]) -> "Event":
        """Parse a wire-format event dict, validating structure (not signature)."""
        try:
            pubkey = data["pubkey"]
            created_at = data["created_at"]
            kind = data["kind"]
            tags = data["tags"]
            content = data["content"]
            event_id = data["id"]
        except (KeyError, TypeError) as exc:
            raise EventValidationError(f"missing event field: {exc}") from exc
        sig = data.get("sig")
        if not isinstance(pubkey, str) or not _is_hex(pubkey, 64):
            raise EventValidationError("pubkey must be 64-char lowercase hex")
        if not isinstance(event_id, str) or not _is_hex(event_id, 64):
            raise EventValidationError("id must be 64-char lowercase hex")
        if sig is not None and (not isinstance(sig, str) or not _is_hex(sig, 128)):
            raise EventValidationError("sig must be 128-char lowercase hex")
        if not isinstance(created_at, int) or isinstance(created_at, bool):
            raise EventValidationError("created_at must be an integer")
        if not isinstance(kind, int) or isinstance(kind, bool) or not 0 <= kind <= 65535:
            raise EventValidationError("kind must be an integer in [0, 65535]")
        if not isinstance(content, str):
            raise EventValidationError("content must be a string")
        if not isinstance(tags, list) or any(
            not isinstance(t, list) or any(not isinstance(v, str) for v in t) for t in tags
        ):
            raise EventValidationError("tags must be a list of lists of strings")
        return cls(
            pubkey=pubkey,
            created_at=created_at,
            kind=kind,
            tags=tuple(tuple(t) for t in tags),
            content=content,
            id=event_id,
            sig=sig,
        )

    @classmethod
    def from_json(cls, raw: str | bytes) -> "Event":
        try:
            data = json.loads(raw)
        except json.JSONDecodeError as exc:
            raise EventValidationError(f"invalid JSON: {exc}") from exc
        if not isinstance(data, dict):
            raise EventValidationError("event JSON must be an object")
        return cls.from_dict(data)

    # -- serialization -----------------------------------------------------

    def to_dict(self) -> dict[str, Any]:
        data: dict[str, Any] = {
            "id": self.id,
            "pubkey": self.pubkey,
            "created_at": self.created_at,
            "kind": self.kind,
            "tags": [list(t) for t in self.tags],
            "content": self.content,
        }
        if self.sig is not None:
            data["sig"] = self.sig
        return data

    def to_json(self) -> str:
        return json.dumps(self.to_dict(), ensure_ascii=False, separators=(",", ":"))

    # -- integrity ---------------------------------------------------------

    def recompute_id(self) -> str:
        return compute_event_id(
            self.pubkey, self.created_at, self.kind, [list(t) for t in self.tags], self.content
        )

    def id_valid(self) -> bool:
        """Does the declared id match the canonical serialization?"""
        return self.id == self.recompute_id()

    def sig_valid(self) -> bool:
        """Is the signature a valid BIP-340 signature by ``pubkey`` over ``id``?

        False when unsigned. Does not check the id itself — use ``verify``.
        """
        if self.sig is None:
            return False
        return _keys.schnorr_verify(self.pubkey, bytes.fromhex(self.id), bytes.fromhex(self.sig))

    def verify(self) -> bool:
        """Full NIP-01 verification: id matches content AND signature is valid.

        This is the platform's trust root — every consumer that reads from a
        relay must call this (or a helper that does) before believing an event.
        """
        return self.id_valid() and self.sig_valid()

    # -- tag access --------------------------------------------------------

    def tag_values(self, name: str) -> Iterator[tuple[str, ...]]:
        """Yield the value portions (everything after the name) of matching tags."""
        for tag in self.tags:
            if tag and tag[0] == name:
                yield tag[1:]

    def first_tag_value(self, name: str) -> str | None:
        """The first value of the first tag named ``name``, or None."""
        for values in self.tag_values(name):
            return values[0] if values else None
        return None

"""Deployment configuration: relay URL, key material, capability attestations.

No new storage systems (DESIGN.md §6.2): configuration is a TOML file read
with stdlib ``tomllib`` plus environment variables. Key material is never
stored in the config file itself — the file names *where* the key lives
(an env var or a file path), and ``load_keypair`` resolves it at runtime.

Capability attestations are the "verify, don't infer" mechanism from the
relay-integration research: relay-side behaviors that degrade silently on a
plain NIP-29 relay (private-group read gating above all) must be explicitly
attested by the deployment operator before the library will rely on them.
Absence of an attestation is a hard "no", not a "probably".
"""

from __future__ import annotations

import os
import tomllib
from pathlib import Path

from pydantic import BaseModel, Field, field_validator

from lindenmayer.core.keys import Keypair

__all__ = [
    "CAP_PRIVATE_READ_GATING",
    "CapabilityAttestation",
    "ConfigError",
    "CoreConfig",
]

# The one degradation that is not cosmetic (research aggregate, finding 4):
# relay-side enforcement of NIP-29 `private` read gating. Buzz satisfies it
# by construction; "NIP-29 compliant" alone does not.
CAP_PRIVATE_READ_GATING = "nip29-private-read-gating"


class ConfigError(ValueError):
    """Raised when configuration is missing, malformed, or unresolvable."""


class CapabilityAttestation(BaseModel):
    """An operator's explicit statement that this deployment's relay enforces
    a capability that the protocol alone does not guarantee.

    This is a config-level record of an operational fact, attributable to
    whoever operates the deployment — not a signed wire event. Consumers
    that need wire-level proof verify from the signed log (verify module).
    """

    capability: str
    attested_by: str = Field(description="operator identity: name or pubkey hex")
    attested_at: int = Field(description="unix timestamp of the attestation")
    note: str = ""

    @field_validator("capability", "attested_by")
    @classmethod
    def _non_empty(cls, value: str) -> str:
        if not value.strip():
            raise ValueError("must be non-empty")
        return value


class CoreConfig(BaseModel):
    """Top-level configuration for a Lindenmayer deployment."""

    relay_url: str
    capability_attestations: list[CapabilityAttestation] = Field(default_factory=list)
    secret_key_env: str = "LINDENMAYER_SECRET_KEY"
    secret_key_file: Path | None = None

    @field_validator("relay_url")
    @classmethod
    def _ws_url(cls, value: str) -> str:
        if not value.startswith(("ws://", "wss://")):
            raise ValueError("relay_url must be a ws:// or wss:// URL")
        return value

    # -- capabilities ------------------------------------------------------

    def has_capability(self, capability: str) -> bool:
        """True only if the deployment explicitly attests ``capability``."""
        return any(a.capability == capability for a in self.capability_attestations)

    def attestation_for(self, capability: str) -> CapabilityAttestation | None:
        for attestation in self.capability_attestations:
            if attestation.capability == capability:
                return attestation
        return None

    # -- key material ------------------------------------------------------

    def load_keypair(self) -> Keypair:
        """Resolve key material: env var first, then key file.

        The secret is 64-char hex. It never transits the config file; a
        world-readable key file is refused outright.
        """
        secret_hex = os.environ.get(self.secret_key_env, "").strip()
        if secret_hex:
            return self._keypair_from_hex(secret_hex, source=f"${self.secret_key_env}")
        if self.secret_key_file is not None:
            path = self.secret_key_file.expanduser()
            if not path.is_file():
                raise ConfigError(f"secret key file not found: {path}")
            mode = path.stat().st_mode & 0o777
            if mode & 0o077:
                raise ConfigError(
                    f"secret key file {path} is group/world-accessible "
                    f"(mode {mode:o}); chmod 600 it"
                )
            return self._keypair_from_hex(path.read_text().strip(), source=str(path))
        raise ConfigError(
            f"no key material: ${self.secret_key_env} is unset and no "
            "secret_key_file is configured"
        )

    @staticmethod
    def _keypair_from_hex(secret_hex: str, *, source: str) -> Keypair:
        try:
            return Keypair.from_hex(secret_hex)
        except ValueError as exc:
            # Deliberately excludes the material itself from the message.
            raise ConfigError(f"invalid secret key from {source}: {exc}") from exc

    # -- loading -----------------------------------------------------------

    @classmethod
    def from_toml(cls, path: str | Path) -> "CoreConfig":
        path = Path(path)
        try:
            data = tomllib.loads(path.read_text())
        except (OSError, tomllib.TOMLDecodeError) as exc:
            raise ConfigError(f"cannot read config {path}: {exc}") from exc
        try:
            return cls.model_validate(data)
        except ValueError as exc:
            raise ConfigError(f"invalid config {path}: {exc}") from exc

"""Shared machinery for kind models: tag/content parsing and event conversion.

Each kind model is a pydantic-v2 model whose fields cover both the
tag-borne and content-borne data of its wire shape. Conversion is
symmetric: ``to_event(pubkey=...)`` assembles an unsigned ``Event``;
``from_event(event)`` validates kind number, required tags, and content
JSON, raising ``KindValidationError`` with a message that names what was
wrong.
"""

from __future__ import annotations

import json
from typing import Any, ClassVar

from pydantic import BaseModel, ConfigDict, ValidationError

from lindenmayer.core.event import Event

__all__ = ["KindModel", "KindValidationError"]


class KindValidationError(ValueError):
    """An event does not conform to the kind schema it was parsed as."""


def _is_hex(value: str, length: int) -> bool:
    if len(value) != length or value != value.lower():
        return False
    try:
        bytes.fromhex(value)
    except ValueError:
        return False
    return True


class KindModel(BaseModel):
    """Base for all Lindenmayer kind models."""

    model_config = ConfigDict(frozen=True, extra="forbid")

    #: The kind number this model maps to (set per subclass from constants).
    KIND: ClassVar[int]

    # -- conversion (per-subclass shape) ----------------------------------

    def event_tags(self) -> list[list[str]]:
        """The tag list for the wire event (subclass responsibility)."""
        raise NotImplementedError

    def event_content(self) -> str:
        """The content string for the wire event (subclass responsibility)."""
        raise NotImplementedError

    @classmethod
    def _from_wire(cls, event: Event) -> dict[str, Any]:
        """Extract constructor kwargs from a wire event (subclass responsibility)."""
        raise NotImplementedError

    # -- public API --------------------------------------------------------

    def to_event(self, *, pubkey: str, created_at: int | None = None) -> Event:
        """Build the unsigned wire event for this model, authored by ``pubkey``."""
        return Event.build(
            pubkey=pubkey,
            kind=self.KIND,
            tags=self.event_tags(),
            content=self.event_content(),
            created_at=created_at,
        )

    @classmethod
    def from_event(cls, event: Event) -> "KindModel":
        """Parse a wire event into this model, validating shape and types."""
        if event.kind != cls.KIND:
            raise KindValidationError(
                f"{cls.__name__} expects kind {cls.KIND}, got kind {event.kind}"
            )
        kwargs = cls._from_wire(event)
        try:
            return cls(**kwargs)
        except ValidationError as exc:
            raise KindValidationError(
                f"kind {cls.KIND} ({cls.__name__}) invalid: {exc}"
            ) from exc

    # -- shared helpers ----------------------------------------------------

    @classmethod
    def _require_tag(cls, event: Event, name: str) -> str:
        value = event.first_tag_value(name)
        if value is None:
            raise KindValidationError(
                f"kind {cls.KIND} ({cls.__name__}) missing required tag '{name}'"
            )
        return value

    @classmethod
    def _content_object(cls, event: Event) -> dict[str, Any]:
        try:
            data = json.loads(event.content)
        except json.JSONDecodeError as exc:
            raise KindValidationError(
                f"kind {cls.KIND} ({cls.__name__}) content is not valid JSON: {exc}"
            ) from exc
        if not isinstance(data, dict):
            raise KindValidationError(
                f"kind {cls.KIND} ({cls.__name__}) content must be a JSON object"
            )
        return data

    @classmethod
    def _require_event_id(cls, value: str, what: str) -> str:
        if not _is_hex(value, 64):
            raise KindValidationError(
                f"kind {cls.KIND} ({cls.__name__}) {what} must be a 64-char "
                f"lowercase hex event id, got {value!r}"
            )
        return value

    @staticmethod
    def _dump_content(data: dict[str, Any]) -> str:
        return json.dumps(data, ensure_ascii=False, separators=(",", ":"))

"""secp256k1 key handling: BIP-340 Schnorr signing and verification.

Thin wrapper over coincurve (libsecp256k1 — the BIP-340 reference C
implementation). This module is the only place in Lindenmayer that touches
raw key material; everything else works with hex pubkeys and `Event`s.

Key-material discipline: secrets live in memory as bytes, are never logged,
and never appear in repr/str output.
"""

from __future__ import annotations

from coincurve.keys import PrivateKey, PublicKeyXOnly

__all__ = ["Keypair", "schnorr_sign", "schnorr_verify"]


def schnorr_verify(pubkey_hex: str, message: bytes, signature: bytes) -> bool:
    """Verify a BIP-340 Schnorr signature by an x-only pubkey over ``message``.

    Returns False (never raises) on malformed keys or signatures — callers
    treat verification failure uniformly regardless of why the input is bad.
    """
    try:
        pubkey = PublicKeyXOnly(bytes.fromhex(pubkey_hex))
        return pubkey.verify(signature, message)
    except Exception:
        return False


def schnorr_sign(secret: bytes, message: bytes, aux_rand: bytes | None = None) -> bytes:
    """Produce a BIP-340 Schnorr signature over ``message``.

    ``aux_rand`` is the 32-byte auxiliary randomness from BIP-340; None lets
    the backend choose (test vectors pass it explicitly).
    """
    key = PrivateKey(secret)
    if aux_rand is None:
        return key.sign_schnorr(message)
    return key.sign_schnorr(message, aux_randomness=aux_rand)


class Keypair:
    """A secp256k1 keypair identified by its x-only public key (hex)."""

    __slots__ = ("_private",)

    def __init__(self, secret: bytes) -> None:
        if len(secret) != 32:
            raise ValueError("secret key must be exactly 32 bytes")
        self._private = PrivateKey(secret)

    @classmethod
    def generate(cls) -> "Keypair":
        return cls(PrivateKey().secret)

    @classmethod
    def from_hex(cls, secret_hex: str) -> "Keypair":
        return cls(bytes.fromhex(secret_hex))

    @property
    def public_key_hex(self) -> str:
        """The 64-char lowercase hex x-only public key (the Nostr pubkey)."""
        return self._private.public_key_xonly.format().hex()

    def sign(self, message: bytes, aux_rand: bytes | None = None) -> bytes:
        if aux_rand is None:
            return self._private.sign_schnorr(message)
        return self._private.sign_schnorr(message, aux_randomness=aux_rand)

    def sign_event(self, event):  # noqa: ANN001, ANN201 — Event typed at call sites; avoids import cycle
        """Return a signed copy of ``event`` authored by this keypair.

        The event's pubkey must already be this keypair's pubkey (the id
        commits to the pubkey, so signing someone else's event body would
        just produce an invalid event).
        """
        from dataclasses import replace

        if event.pubkey != self.public_key_hex:
            raise ValueError("event.pubkey does not match this keypair")
        if not event.id_valid():
            raise ValueError("event id does not match its canonical serialization")
        signature = self.sign(bytes.fromhex(event.id))
        return replace(event, sig=signature.hex())

    def __repr__(self) -> str:  # never leak the secret
        return f"Keypair(pubkey={self.public_key_hex})"

def _matches(event_data: dict[str, Any], filt: dict[str, Any]) -> bool:
    if "ids" in filt and event_data["id"] not in filt["ids"]:
        return False
    if "authors" in filt and event_data["pubkey"] not in filt["authors"]:
        return False
    if "kinds" in filt and event_data["kind"] not in filt["kinds"]:
        return False
    for key, values in filt.items():
        if key.startswith("#") and len(key) == 2:
            tag_name = key[1]
            tag_values = {
                t[1] for t in event_data.get("tags", []) if len(t) > 1 and t[0] == tag_name
            }
            if not tag_values & set(values):
                return False
    return True

