import ast, pathlib
for f in pathlib.Path('src/lindenmayer/evergreen').glob('*.py'):
    tree = ast.parse(f.read_text())
    imported = set()
    for n in ast.walk(tree):
        if isinstance(n, ast.Import):
            for a in n.names: imported.add((a.asname or a.name).split('.')[0])
        elif isinstance(n, ast.ImportFrom):
            for a in n.names: imported.add(a.asname or a.name)
    src = f.read_text()
    body = "\n".join(l for l in src.splitlines() if not l.strip().startswith(('import ','from ')))
    unused = [i for i in imported if i not in body and i != 'annotations']
    print(f.name, "unused:", unused or "none")
EOF
